class Solution {
    public int evalRPN(String[] tokens) {
        Deque<Integer> stack = new ArrayDeque<>();
        for (String t : tokens) {
            switch (t) {
                case "+": stack.push(stack.pop() + stack.pop()); break;
                case "-": {
                    int b = stack.pop();
                    stack.push(stack.pop() - b);
                    break;
                }
                case "*": stack.push(stack.pop() * stack.pop()); break;
                case "/": {
                    int b = stack.pop();
                    stack.push(stack.pop() / b);
                    break;
                }
                default: stack.push(Integer.parseInt(t));
            }
        }
        return stack.pop();
    }
}

